<script setup>
import InboxHeader from './InboxHeader.vue'
import ConversationItem from './ConversationItem.vue'
import LoginCTA from './LoginCTA.vue'

defineProps({
  title: { type: String, default: '消息' },
  pinnedAgent: { type: Object, default: null },  // {name, last_message, last_at, avatarSrc?}
  conversations: { type: Array, default: () => [] },
  loading: { type: Boolean, default: false },
  loggedIn: { type: Boolean, default: true },
  emptyHint: { type: String, default: '还没有真人消息' },
  emptyDetail: { type: String, default: '先跟 agent 聊配 profile · 等推荐进来后会出现' },
})
defineEmits(['refresh', 'open-agent', 'open-conversation', 'login'])
</script>

<template>
  <div class="h-screen flex flex-col max-w-2xl mx-auto bg-akong-paper">
    <InboxHeader :title="title" :loading="loading" @refresh="$emit('refresh')" />

    <main class="flex-1 overflow-y-auto" data-testid="inbox-list">
      <!-- 置顶: agent · 永远显示 (无论是否登录) -->
      <ConversationItem
        v-if="pinnedAgent"
        :name="pinnedAgent.name"
        :avatar-src="pinnedAgent.avatarSrc"
        :last-message="pinnedAgent.last_message || '跟我聊配 profile'"
        :last-at="pinnedAgent.last_at"
        :unread-count="pinnedAgent.unread_count || 0"
        pinned
        data-testid="conv-agent"
        @click="$emit('open-agent')"
      >
        <template #avatar><slot name="agent-avatar"></slot></template>
      </ConversationItem>

      <!-- 未登录 placeholder -->
      <LoginCTA v-if="!loggedIn" @login="$emit('login')" />

      <!-- 已登录加载中 -->
      <div
        v-else-if="loading"
        class="p-8 text-center text-akong-muted text-sm"
        data-testid="loading"
      >加载中…</div>

      <!-- 已登录无对话 -->
      <div
        v-else-if="conversations.length === 0"
        class="p-8 text-center"
        data-testid="empty"
      >
        <div class="text-4xl mb-3">📭</div>
        <p class="text-sm text-akong-ink mb-1">{{ emptyHint }}</p>
        <p class="text-xs text-akong-muted">{{ emptyDetail }}</p>
      </div>

      <!-- 已登录列表 -->
      <ConversationItem
        v-for="c in conversations"
        v-else
        :key="`${c.peer_kind}-${c.peer_id}`"
        :name="c.name"
        :avatar-src="c.avatarSrc"
        :last-message="c.last_message"
        :last-at="c.last_at"
        :unread-count="c.unread_count"
        :badge="c.peer_kind === 'org_member' ? '机构' : ''"
        :data-testid="`conv-${c.peer_id}`"
        @click="$emit('open-conversation', c)"
      />
    </main>
  </div>
</template>
